item.content:
&lt;div class=&quot;row&quot;&gt;
	&lt;div class=&quot;col-sm-12 col-md-12&quot;&gt;&lt;img id=&quot;bor&quot; src=&quot;data/uploads/innerbanner2.jpg&quot; width=&quot;100%&quot; /&gt;&lt;/div&gt;
	&lt;div class=&quot;col-sm-12 col-md-12&quot;&gt;&lt;br /&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;strong&gt;Dr. K. Sendhil Kumar Is One Of The Most Renowned Surgical Gastroenterologists&lt;/strong&gt;, Who Graduated MBBS And MS (General Surgery) From Coimbatore Medical College, Tamilnadu And DNB (Surgical Gastroenterology) From Prestigious Gem Hospital, Coimbatore, Where He Worked Under Professor Dr. C. Palanivelu From March 1995 To March 2009.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;In A Nationwide Exam Conducted By The National Board Of Examination (NBE), He Was The Only One To Clear Theory Exam In The Whole Country.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;Then He Appeared For The Practical Examination At The Christian Medical College (CMC), Vellore And Cleared In The First Attempt. This Was Well Appreciated By Follow Gastro Surgeons.&lt;/p&gt;
	&lt;/div&gt;
	&lt;div class=&quot;col-sm-12 col-md-12&quot;&gt;
		&lt;div class=&quot;row&quot;&gt;
			&lt;div class=&quot;col-sm-6 col-md-6&quot;&gt;&lt;iframe allow=&quot;autoplay; encrypted-media&quot; allowfullscreen=&quot;&quot; frameborder=&quot;0&quot; height=&quot;315&quot; src=&quot;https://www.youtube.com/embed/0v1niHkbI9A?rel=0&amp;amp;controls=0&amp;amp;showinfo=0&quot; width=&quot;100%&quot;&gt;&lt;/iframe&gt;&lt;/div&gt;
			&lt;div class=&quot;col-sm-6 col-md-6&quot;&gt;&lt;iframe allow=&quot;autoplay; encrypted-media&quot; allowfullscreen=&quot;&quot; frameborder=&quot;0&quot; height=&quot;315&quot; src=&quot;https://www.youtube.com/embed/63jEdwwjR_E?rel=0&amp;amp;controls=0&amp;amp;showinfo=0&quot; width=&quot;100%&quot;&gt;&lt;/iframe&gt;&lt;/div&gt;
		&lt;/div&gt;
	&lt;/div&gt;
	&lt;div class=&quot;col-sm-12 col-md-12&quot;&gt;
		&lt;h5&gt;Present Position:&lt;/h5&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Chairman And Chief Surgical Gastroenterologist, Gateway Clinics And Hospitals, Coimbatore.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Teaching Faculty For Various Basic And Advanced Laparoscopic Surgery Training Courses.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Visiting Consultants In Surgical Gastroenterology At Vedanayagam And KC Hospitals, Coimbatore.&lt;/p&gt;
		&lt;h5&gt;Special Training and Experience:&lt;/h5&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Endoscopy, Colonoscopy - Diagnostic and Therapeutic.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; a. Therapeutic upper Gastro procedures like band ligation and sclerotherapy of oesophageal varices, removal of polyps, balloon dilatation for Achalasia Cardia, Oesophageal stenting etc.,&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; b. Therapeutic Colonoscopy procedures like Polypectomy, stenting etc.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;ERCP for removal of CBD stones and Stenting for obstructive jaundice, biliary strictures and pancreatic diseases.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Basic Laparoscopy:&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; a. Laparoscopic Appendectomy, Cholecystectomy.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; b. Laparoscopic Inguinal , Femoral And Abdominal (Umbilical,Paraumbilical, Incisional, Spigelian, Epigastric, Internal ) Hernia Mesh Repair.&lt;br /&gt;
			Eg : IPOM, TEP, TAPP Repair Methods.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; c. Laparoscopic Ovarian Cystectomy, Oophorectomy.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; d. Laparoscopic Ectopic Pregnancy Management.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; e. Total Laparoscopic Hysterectomy.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Advanced Laparoscopy:&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; a. Laparoscopic Oesophagogastrectomy, Radical D2 Gastrectomy For Gastric Cancer Total Radical Gastrectomy With Jejunal Pouch - Oesophageal Anastomosis.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; b. Laparoscopic Right Hemicolectomy&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; c. Laparoscopic Left Hemicolectomy, Anterior Resection (LAR), Abdomino Perineal Resection (APR)&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; d. Laparoscopic Rectopexy for Rectal prolapse&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; e. Total ProctoColectomy with Ileal Pouch Anal Anastomosis (TPC with IPAA) for ulcerative colitis&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; f. Whipple&#039;s procedure for head of pancreas cancers.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; g. Laparoscopic Distal Pancreatectomy&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; h. Laparoscopic Radical Cholecystectomy, CBD Exploration&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; &amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; &amp;gt;&amp;gt; Laparoscopic Management Of Gastro Emergencies (Acute Abdomen)&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; &amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; &amp;gt;&amp;gt; Laparoscopic Solid Organ Surgeries - Complicated Pancreatic And Liver And Spleen Surgery.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; &amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp; &amp;gt;&amp;gt; Laparoscopic Repair Of Hiatus Hernia.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Stapler Haemorrhoidectomy.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;Anal Fissure And Anal Fistula Surgeries.&lt;/p&gt;
		&lt;h5&gt;Academics &amp;amp; Research work publication:&lt;/h5&gt;
		&lt;p align=&quot;justify&quot;&gt;Being A Keen Academic, He Has To His Credit Of Over 100 Presentations And Invited Lectures At National And International Conferences. He Has Also Written Many Articles In National International Journals. Dr. K. Sendhil Kumar Firmly Believes That The Benefits Of Laparoscopic And Thorocoscopic Surgery Should Be Passed On To One And All Irrespective Of Socioeconomic Status.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;He Is A Teaching Faculty Of The Basic And Advanced Laparoscopic Surgery Courses Conducted At Regular Intervals And Also Participated In Various Live Laparoscopic Workshops.&lt;/p&gt;
		&lt;h5&gt;Additional Degrees and Professional Memberships:&lt;/h5&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;&lt;strong&gt;IMA&lt;/strong&gt; (Indian Medical Association)&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;&lt;strong&gt;FICS &lt;/strong&gt;(Fellow International College of Surgeons)&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;&lt;strong&gt;FACS&lt;/strong&gt; (Fellow American College of Surgeons)&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;&lt;strong&gt;FAIS&lt;/strong&gt; (Fellow of Association of Indian Surgeons)&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;&lt;strong&gt;ASI&lt;/strong&gt; (Association of Surgeons of India)&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;&lt;strong&gt;AMASI&lt;/strong&gt; (Association of Minimal Access Surgeons of India)&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;&lt;img class=&quot;space&quot; src=&quot;data/uploads/fav-icon.png&quot; /&gt;&lt;strong&gt;IAGES&lt;/strong&gt; (Indian Association of Gastrointestinal Endoscopic Surgeons)&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;We Look Forward to Offer Our Patients The Benefit Of State Of The Art Techniques Of Minimally Invasive Gastro Surgery.&lt;/p&gt;
		&lt;p align=&quot;justify&quot;&gt;(% gallery name=chairman %)&lt;/p&gt;
	&lt;/div&gt;
&lt;/div&gt;
&lt;p&gt;&amp;nbsp;&lt;/p&gt;
